func isPalindrome(_ str: String) -> Bool {
    let cleanedString = str.lowercased().filter { $0.isLetter || $0.isNumber }
    return cleanedString == String(cleanedString.reversed())
}

// Giải thích:
// 1. `lowercased()`: Chuyển chuỗi về chữ thường để bỏ qua sự khác biệt về hoa thường.
// 2. `filter { $0.isLetter || $0.isNumber }`: Loại bỏ các ký tự không phải chữ cái hoặc số.
// 3. `reversed()`: Đảo ngược chuỗi đã làm sạch.
// 4. So sánh chuỗi đã làm sạch với chuỗi đảo ngược. Nếu bằng nhau, chuỗi là palindrome.
```

