import UIKit

func saveString(key: String, value: String) {
    let defaults = UserDefaults.standard
    defaults.set(value, forKey: key)
    defaults.synchronize() // Đảm bảo dữ liệu được lưu ngay lập tức
}

func loadString(key: String) -> String? {
    let defaults = UserDefaults.standard
    return defaults.string(forKey: key)
}

// Ví dụ sử dụng:
// saveString(key: "myString", value: "Hello, world!")
// if let myString = loadString(key: "myString") {
//     print(myString)
// }

// Giải thích:
// 1. `UserDefaults.standard`: Lấy đối tượng UserDefaults mặc định.
// 2. `set(value, forKey:)`: Lưu giá trị vào UserDefaults với key tương ứng.
// 3. `synchronize()`: Đảm bảo dữ liệu được lưu vào đĩa ngay lập tức.
// 4. `string(forKey:)`: Lấy giá trị từ UserDefaults với key tương ứng. Trả về nil nếu key không tồn tại.
